const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export function processScenario(scenario: {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
}): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBasePremium = items.reduce(
      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
      0
    );
    const firstInsurance = policyBasePremium * 0.1;
    const premium = policyBasePremium + firstInsurance + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}
